321	task data2sram;
322	  begin
323		// reset tmp_mat1, tmp_mat2, tmp_c_mat1, tmp_c_mat2
324		for(i = 0; i< ARRAY_SIZE ; i = i + 1) begin
325			tmp_c_mat1[i] = 0;
326			tmp_c_mat2[i] = 0;
327			tmp_mat1[i] = 0;
328			tmp_mat2[i] = 0;
329		end	
330		// combine three batch together into tmp_mat1, tmp_mat2
331		for(i = 0; i< 3 ; i = i + 1) begin
332			for(j = 0; j< ARRAY_SIZE; j = j+1)begin
333				tmp_c_mat1[j] = {mat1[ARRAY_SIZE*i+j], tmp_c_mat1[j][(ARRAY_SIZE*3*DATA_WIDTH-1) -: 2*DATA_WIDTH*ARRAY_SIZE]};
334				tmp_c_mat2[j] = {mat2[ARRAY_SIZE*i+j], tmp_c_mat2[j][(ARRAY_SIZE*3*DATA_WIDTH-1) -: 2*DATA_WIDTH*ARRAY_SIZE]};
335			end
336		end
337		for(i = 0; i< ARRAY_SIZE ; i = i + 1) begin
338			case (i % 4)
339				0 : begin
340					tmp_mat1[i] = {24'b0, tmp_c_mat1[i]};
341					tmp_mat2[i] = {24'b0, tmp_c_mat2[i]};
342				    end
343				1 : begin
344					tmp_mat1[i] = {16'b0, tmp_c_mat1[i], 8'b0};
345					tmp_mat2[i] = {16'b0, tmp_c_mat2[i], 8'b0};
346				    end
347				2 : begin
348					tmp_mat1[i] = {8'b0, tmp_c_mat1[i], 16'b0};
349					tmp_mat2[i] = {8'b0, tmp_c_mat2[i], 16'b0};
350				    end
351				3 : begin
352					tmp_mat1[i] = {tmp_c_mat1[i], 24'b0};
353					tmp_mat2[i] = {tmp_c_mat2[i], 24'b0};
354				    end
355				default : begin
356						tmp_mat1[i] = 0;
357						tmp_mat2[i] = 0;
358					  end
359			endcase
360		end
361		
362		for(i = 0; i < 128; i=i+1)begin
