418	task golden_transform;
419	integer this_i, this_j, this_k;
420	  begin
421		for(this_k=0; this_k<(ARRAY_SIZE*2-1);this_k = this_k +1)begin	  
422			trans_golden1[this_k] = 0;
423			trans_golden2[this_k] = 0;
424			trans_golden3[this_k] = 0;
425		end
426		for(this_k=0; this_k<(ARRAY_SIZE*2-1);this_k = this_k +1)begin	  
427			for(this_i=0;this_i<ARRAY_SIZE;this_i=this_i+1) begin
428	            		for(this_j=0;this_j<ARRAY_SIZE;this_j=this_j+1) begin
429					if((this_i+this_j)==this_k)begin
